function solve(grid) {
  let rowHeights = [];
  for (let i = 0; i < grid.length; i++) {
    let maxHeight = 0;
    for (let j = 0; j < grid[i].length; j++) {
      maxHeight = Math.max(maxHeight, grid[i][j]);
    }
    rowHeights.push(maxHeight);
  }
  return rowHeights;
}

